            // Assert
            result.Should().NotBeNull();
            result.Value.parametros.Should().HaveCount(2);
            var startParameter = result.Value.parametros.FirstOrDefault(p => p.ParameterName == $"@{DBModelosDocumentosDicInfo.DtCad}");
            var endParameter = result.Value.parametros.FirstOrDefault(p => p.ParameterName == $"@{DBModelosDocumentosDicInfo.DtCad}_end");
            startParameter.Should().NotBeNull();
            endParameter.Should().NotBeNull();
            startParameter!.Value.Should().BeOfType<DateTime>();
            endParameter!.Value.Should().BeOfType<DateTime>();
            ((DateTime)startParameter.Value).Should().Be(DateTime.Parse(startDate));
            ((DateTime)endParameter.Value).Should().Be(DateTime.Parse(endDate));
            result.Value.where.Should().Contain($"[{DBModelosDocumentosDicInfo.PTabelaNome}].{DBModelosDocumentosDicInfo.DtCad} BETWEEN @{DBModelosDocumentosDicInfo.DtCad} AND @{DBModelosDocumentosDicInfo.DtCad}_end");
