            endParameter!.Value.Should().BeOfType<DateTime>();
            ((DateTime)startParameter.Value).Should().Be(DateTime.Parse(startDate));
            ((DateTime)endParameter.Value).Should().Be(DateTime.Parse(endDate));
            result.Value.where.Should().Contain($"[{DBModelosDocumentosDicInfo.PTabelaNome}].{DBModelosDocumentosDicInfo.DtAtu} BETWEEN @{DBModelosDocumentosDicInfo.DtAtu} AND @{DBModelosDocumentosDicInfo.DtAtu}_end");
        }

